# coding: utf-8
import json
from typing import List, Optional, TYPE_CHECKING
from rainbow_admin.errors import RainbowException

if TYPE_CHECKING:
    from rainbow_admin import RainbowAdmin


class GrayRuleType(object):
    def __init__(self, type_id: int, type_name: str, src_page_type: int, **kwargs):
        self.type_id = type_id
        self.type_name = type_name
        self.src_page_type = src_page_type


class GrayRule(object):
    def __init__(
        self,
        gray_rule_type_id: int,
        gray_rule_type_name: str,
        case_content: str,
        gray_rule_id: int = 0,
        **kwargs,
    ):
        self.content = case_content
        self.rule_id = gray_rule_id
        self.rule_type_id = gray_rule_type_id
        self.rule_type_name = gray_rule_type_name


class TagOperator(object):
    IN = "in"
    MATCH = "match"


class StepStatus(object):
    ON = "Gray_Rule_Step_Status_PUBLISHED"
    OFF = "Gray_Rule_Step_Status_INIT"


class GrayStep(object):
    def __init__(self, name: str, tag: str = None, operator: TagOperator = None, content: str = None):
        self.step_name = name
        self.tag_match_contents = list()
        if tag and operator and content:
            self.add_tag(tag, operator, content)

    def add_tag(self, tag: str = None, operator: TagOperator = None, content: str = None):
        """修改发布任务的灰度步骤，使用全量覆盖模式来提交
        :param tag: 自定义传递的标签名
        :param operator: 当前支持：在列表中（TagOperator.IN）、正则匹配（TagOperator.MATCH）
        :param content: 用于判断的标签值，用,来分隔多个取值。如 10.0.0.1,10.0.0.2
        """
        if tag and operator and content:
            self.tag_match_contents.append(
                dict(
                    match_plugin_tag_name=tag,
                    match_plugin_name=operator,
                    match_content=content,
                )
            )
        else:
            raise RainbowException("tag, operator, content should be set")
        return self

    @property
    def text(self):
        return self.__str__()

    @property
    def json(self):
        return dict(
            step_name=self.step_name,
            tag_match_contents=self.tag_match_contents,
        )

    def ON(self):
        return GrayStepStatus(StepStatus.ON)

    def OFF(self):
        return GrayStepStatus(StepStatus.OFF)

    def __str__(self):
        return json.dumps(self.json)

    __repr__ = __str__
    decode = __str__


class GrayStepStatus(GrayStep):
    def __init__(
        self,
        name: str,
        status: StepStatus,
    ):
        super(GrayStepStatus, self).__init__(name)
        self.status = status

    def ON(self):
        self.status = StepStatus.ON

    def OFF(self):
        self.status = StepStatus.OFF

    @property
    def text(self):
        return self.__str__()

    @property
    def json(self):
        return dict(
            step_name=self.step_name,
            status=self.status,
            tag_match_contents=self.tag_match_contents,
        )


class Release(object):
    def __init__(
        self,
        task_id,
        version_name,
        group_name,
        apply_user,
        status,
        approval_user,
        description,
        create_time,
        prev_version_name,
        admin: "RainbowAdmin",
        **kwargs,
    ):
        self.task_id = task_id
        self.version_name = version_name
        self.apply_user = apply_user
        self.status = status
        self.approval_user = approval_user
        self.description = description
        self.create_time = create_time
        self.prev_version_name = prev_version_name

        self.admin = admin
        self.group = self.admin.get_group(group_name)

        self.infos = kwargs

    def get_info(self):
        return self.admin.api.query_task_info(self.task_id)

    def agree(self):
        return self.admin.api.approval_release_task(
            self.group.group_name,
            'WAIT_RELEASE',
            task_id=self.task_id,
        )

    def reject(self, reason):
        return self.admin.api.approval_release_task(
            self.group.group_name,
            'APPROVAL_REJECT',
            task_id=self.task_id,
            reject_reason=reason,
        )

    def cancel(self):
        return self.admin.api.cancel_release_task(
            self.group.group_name,
            self.admin.env,
            self.task_id,
        )

    def get_gray_steps(self):
        rsp = self.admin.api.query_multi_step_gray_case(
            self.admin.env,
            self.group.group_id,
            self.group.group_name,
            self.task_id,
        )
        if not rsp['ret_code'] == 0:
            raise RainbowException(f"{rsp}")
        steps = list()
        for item in rsp['multi_step_gray_contents']:
            step = GrayStepStatus(item['step_name'], item['status'])
            for content in item['tag_match_contents']:
                step.add_tag(
                    content['match_plugin_tag_name'],
                    content['match_plugin_name'],
                    content['match_content']
                )
            steps.append(step)
        return steps

    def change_gray_steps(self, gray_steps: List[GrayStep]):
        """修改发布任务的灰度步骤，使用全量覆盖模式来提交"""
        return self.admin.api.change_multi_step_gray_case(
            self.admin.env,
            self.group.group_id,
            self.group.group_name,
            self.task_id,
            [i.json for i in gray_steps],
        )

    def gray_batch(self, gray_step_status: List[GrayStepStatus]):
        """对灰度步骤执行批量发布"""
        return self.admin.api.release_multi_step_gray_task(
            self.admin.env,
            self.group.group_id,
            self.group.group_name,
            self.task_id,
            [i.json for i in gray_step_status],
        )

    def gray_next(self) -> GrayStepStatus:
        steps = self.get_gray_steps()
        for i in range(len(steps)):
            if steps[i].status == StepStatus.OFF:
                steps[i].status = StepStatus.ON
                self.gray_batch(steps)
                return steps[i]
            if i == len(steps) - 1:
                return None

    def rollback_last(self) -> GrayStepStatus:
        steps = self.get_gray_steps()
        for i in range(len(steps) - 1, -1, -1):
            if steps[i].status == StepStatus.ON:
                steps[i].status = StepStatus.OFF
                self.gray_batch(steps)
                return steps[i]
            if i == 0:
                return None

    def all_in(self):
        """全量发布"""
        self.admin.api.release_main_task(
            self.task_id, self.group.group_id, self.group.group_name
        )

    def gray(self):
        self.admin.api.release_gray_task(
            self.task_id, self.group.group_id, self.group.group_name
        )

    def rollback(self):
        self.admin.api.rollback_release(
            self.task_id, self.group.group_id, self.group.group_name
        )

    def close_task(self):
        self.admin.api.close_release_task(
            self.task_id, self.group.group_id, self.group.group_name
        )

    def gray_rule(self) -> Optional[GrayRule]:
        case = self.admin.api.query_gray_case(self.group.group_id, self.task_id)
        return GrayRule(**case) if case else None

    def set_gray_rule(self, rule_type: GrayRuleType, rule_content: str):
        op = "GRAY_RULE_ADD"
        if self.gray_rule():
            op = "GRAY_RULE_UPDATE"
        return self.admin.api.change_gray_case(
            self.group.group_id,
            self.group.group_name,
            self.task_id,
            op,
            0,
            rule_type.type_id,
            rule_type.type_name,
            rule_content,
        )

    @property
    def rule_types(self) -> List[GrayRuleType]:
        return self.admin.rule_types

    def __repr__(self) -> str:
        return f"{self.__class__.__name__}(version_name={self.version_name})"
